1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 10;
3	const PERCENT_BASE = 100;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	interface Item {
15	  type: string;
16	  cursed?: boolean;
17	  enchantment?: number;
18	  material?: string;
19	}
20	
21	interface Step {
22	  op: string;
23	  items?: Item[];
24	}
25	
26	interface Scenario {
27	  customer: { yearsWithMHPCO: number };
28	  steps: Step[];
29	}
30	
31	const BLOCK_SIZE = 3;
32	const BLOCK_PREMIUM = 60;
33	const CURSE_SURCHARGE_PERCENT = 50;
34	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	const LOYALTY_DISCOUNT_PERCENT = 20;
37	const LOYALTY_THRESHOLD_YEARS = 2;
38	const FOLLOWUP_DISCOUNT_PERCENT = 15;
39	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
40	
41	interface Customer {
42	  yearsWithMHPCO: number;
43	}
44	
45	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
46	
47	const percentOf = (amount: number, percent: number): number =>
48	  (amount * percent) / PERCENT_BASE;
49	
50	const percentIf = (condition: boolean, base: number, percent: number): number =>
51	  condition ? percentOf(base, percent) : 0;
52	
53	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type];
54	
55	const itemSurcharges = (item: Item): number => {
56	  const base = BASE_PREMIUM[item.type];
57	  const curse = percentIf(item.cursed === true, base, CURSE_SURCHARGE_PERCENT);
58	  const highEnchantment = percentIf(
59	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
60	    base,
61	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
62	  );
63	  return curse + highEnchantment;
64	};
65	
66	const sumBase = (items: Item[]): number =>
67	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
68	
69	const sumSurcharges = (items: Item[]): number =>
70	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
71	
72	const partitionByType = (items: Item[]): Item[][] => {
73	  const groups: Record<string, Item[]> = {};
74	  items.forEach((item) => (groups[item.type] ??= []).push(item));
75	  return Object.values(groups);
76	};
77	
78	const isComponentBlock = (group: Item[]): boolean =>
79	  group.length === BLOCK_SIZE && isComponent(group[0]);
80	
81	const priceGroup = (group: Item[]): number =>
82	  isComponentBlock(group) ? BLOCK_PREMIUM : sumBase(group);
83	
84	const sumBasePremiums = (items: Item[]): number =>
85	  partitionByType(items).reduce((sum, group) => sum + priceGroup(group), 0);
86	
87	const isLoyalCustomer = (customer: Customer): boolean =>
88	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
89	
90	const applyPolicyModifiers = (
91	  base: number,
92	  customer: Customer,
93	  isFollowUp: boolean,
94	): number => {
95	  const firstInsurance = percentOf(base, FIRST_INSURANCE_PERCENT);
96	  const loyalty = percentIf(isLoyalCustomer(customer), base, LOYALTY_DISCOUNT_PERCENT);
97	  const followUp = percentIf(isFollowUp, base, FOLLOWUP_DISCOUNT_PERCENT);
98	  return base + firstInsurance - loyalty - followUp;
99	};
100	
101	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
102	  const policyBase = sumBasePremiums(items);
103	  const surcharges = sumSurcharges(items);
104	  return Math.ceil(applyPolicyModifiers(policyBase, customer, isFollowUp) + surcharges) + PROCESSING_FEE;
105	};
106	
107	const executeStep = (
108	  step: Step,
109	  customer: Customer,
110	  isFollowUp: boolean,
111	): { premium: number } => ({
112	  premium: quotePremium(step.items ?? [], customer, isFollowUp),
113	});
114	
115	const isQuote = (step: Step): boolean => step.op === "quote";
116	
117	const precedingQuoteCount = (steps: Step[], index: number): number =>
118	  steps.slice(0, index).filter(isQuote).length;
119	
120	export const runScenario = (input: unknown): { results: unknown[] } => {
121	  const scenario = input as Scenario;
122	  return {
123	    results: scenario.steps.map((step, index) =>
124	      executeStep(
125	        step,
126	        scenario.customer,
127	        isQuote(step) && precedingQuoteCount(scenario.steps, index) > 0,
128	      ),
129	    ),
130	  };
131	};
